  IO_ddr_dqs(1 downto 0) => IO_ddr_dqs(1 downto 0),
  IO_ddr_dqs_n(1 downto 0) => IO_ddr_dqs_n(1 downto 0),
  IO_ddr_dq(15 downto 0) => IO_ddr_dq(15 downto 0));
  clk_out <= NN;
  ddr_rst <= NN_0;
  init_calib_complete <= NN_1;
  rd_data_end <= NN_2;
  rd_data_valid <= NN_2;
  sr_ack <= NN_3;
  wr_data_rdy <= NN_4;
end beh;
